let type = flow.get('product_type');
let quantite = flow.get('nb_product');

if (!type || !quantite) {
    node.warn("Incomplete input");
    return null; 
}

msg.topic = "INSERT INTO Orders (nb_product, product_type, status) VALUES (?, ?, 'WAITING');";
msg.payload = [quantite, type];

return msg;

msg.topic = `
    SELECT o.order_id, o.product_type, p.* FROM Orders o 
    JOIN Products p ON o.product_type = p.product_type 
    WHERE o.status = 'WAITING' 
    LIMIT 1;
`;
return msg;

let order_id = msg.order_id;

let sn = order_id + "_" + Date.now();

msg.numSerie = sn;

msg.topic = "INSERT INTO Production (productSN, order_id, cart_id, current_station, status) VALUES (?, ?, 1, 'Station1', 'IN_PROGRESS');";

msg.payload = [sn, order_id];

return msg;

let data = msg.payload[0]; 

msg.order_id = data.order_id;
msg.productData = data;
msg.topic = "UPDATE Orders SET status = 'IN_PROGRESS' WHERE order_id = ?;";

msg.payload = [data.order_id];

return msg;

let fleet = global.get('factory_fleet');
let priorityType = global.get('production_priority');
let order = msg.payload;

let data = msg.productData;

let sn = msg.numSerie; 

let freeCart = fleet.find(c => c.sn === null);

if (freeCart) {
    freeCart.sn = msg.numSerie; 
    freeCart.state = 'EVALUATION';
    freeCart.currentStation = 1;
    freeCart.productData = msg.productData;
    freeCart.isBypassed = false;
    freeCart.order_id = data.order_id,
    global.set('factory_fleet', fleet);

    msg.payload = { action: 'DECISION', sn: freeCart.sn };
    return msg;
} else {
    node.warn("No free carts available");
    return null;
}

let sn = msg.payload.sn;

let fleet = global.get('factory_fleet');
let stations = global.get('factory_stations');

let cart = fleet.find(c => c.sn === sn);

if (!cart) return null;
if (cart.state !== 'EVALUATION') return null;

let numStation = cart.currentStation;

if (numStation > 6) {
    msg.topic = "UPDATE Production SET status = 'FINISHED' WHERE productSN = ?;";
    msg.payload = [sn];
    msg.order_id = cart.order_id;
    msg.productSN = sn;
    msg.next_product = true;

    stations[6] = null;

    let cartId = cart.cart_id; 
    cart.sn = null;
    cart.order_id = null;
    cart.productData = null;
    cart.currentStation = 0;
    cart.state = 'IDLE';
    cart.isBypassed = false;

    global.set('factory_fleet', fleet);
    global.set('factory_stations', stations);

    return [msg, { payload: `[Product ${sn}] Production finished ! Cart ${cartId} is now FREE.` }];
}

stations[numStation] = cart.sn;
if (numStation > 1) {
    stations[numStation - 1] = null;
}

let dbUpdateMsg = {
    topic: "UPDATE Production SET current_station = ? WHERE productSN = ?;",
    payload: ["Station" + numStation, sn]
};

let commandMsg = { payload: {} };
let stopCol = "Station" + numStation + "Stop";
let opCol = "Station" + numStation + "Op";

cart.state = 'ACK_WAIT';

if (cart.productData[stopCol] === 1 || cart.productData[stopCol] === true) {
    cart.isBypassed = false;
    commandMsg.payload = `[Cart ${cart.cart_id} | Product ${sn} -> Station ${numStation}] INSTRUCTION : ${cart.productData[opCol]}`;
} else {
    cart.isBypassed = true;
    commandMsg.payload = `[Cart ${cart.cart_id} | Product ${sn} -> Station ${numStation}] CHECK-IN ONLY (Bypass)`;
}

global.set('factory_fleet', fleet);
global.set('factory_stations', stations);

return [dbUpdateMsg, commandMsg];

let machineAnswer = msg.payload; 
let sn = machineAnswer.sn;

let fleet = global.get('factory_fleet');
let stations = global.get('factory_stations'); 

if (!fleet || !stations) return null; 

let cart = fleet.find(c => c.sn === sn);

if (!cart || cart.state === 'IDLE') return null;

let nextStation = cart.currentStation + 1;

if (machineAnswer.response === "ACK" && cart.state === 'ACK_WAIT') {

    if (cart.isBypassed === true) {
        if (stations[nextStation] === null || nextStation > 6) {
            cart.state = 'EVALUATION';
            cart.currentStation++;

            global.set('factory_fleet', fleet);

            return [
                { payload: `[Cart ${cart.cart_id}] ACK received. BYPASSING... MOVE CART !` }, 
                { payload: { action: 'DECISION', sn: sn } } 
            ];
        } else {
            cart.state = 'BLOCKED';
            global.set('factory_fleet', fleet);
            return { payload: `[Cart ${cart.cart_id}] BYPASSED but PATH BLOCKED at Station ${nextStation}. Waiting...` };
        }
    } else {
        cart.state = 'DONE_WAIT';
        global.set('factory_fleet', fleet);
        return { payload: `[Cart ${cart.cart_id}] ACK received. Operation in progress...` };
    }
}

if (machineAnswer.response === "DONE" && cart.state === 'DONE_WAIT') {

    if (stations[nextStation] === null || nextStation > 6) {
        cart.state = 'EVALUATION';
        cart.currentStation++;

        global.set('factory_fleet', fleet);

        return [
            { payload: `[Cart ${cart.cart_id}] DONE received. MOVE CART !` }, 
            { payload: { action: 'DECISION', sn: sn } } 
        ];

    } else {
        cart.state = 'BLOCKED';
        global.set('factory_fleet', fleet);
        return { payload: `[Cart ${cart.cart_id}] DONE received but PATH BLOCKED at Station ${nextStation}. Waiting...` };
    }
}

return null;

if (!Array.isArray(msg.payload)) {
    return null;
}

msg.options = msg.payload.map(row => row.product_type);

msg.payload = "";

return msg;

if (!msg.next_product) {
    return null;
}

msg.payload = [msg.order_id];

msg.topic = `
    SELECT
        p.productSN, p.order_id, p.cart_id, p.status,
        o.nb_product,
        pr.*
    FROM Production p
    JOIN Orders o ON p.order_id = o.order_id
    JOIN Products pr ON pr.product_type = o.product_type
    WHERE p.status = 'FINISHED' AND p.order_id = ?;
`;

return msg;

let totalProducts = msg.payload[0].nb_product;
let finishedProducts = msg.payload.length;

let remainingProducts = totalProducts - finishedProducts;
msg.remainingProducts = remainingProducts;

if (remainingProducts > 0) {
    msg.productData = msg.payload[0];
    msg.order_id = msg.payload[0].order_id;
    msg.production_status = "PENDING";
    return [msg, null]; 
} else {
    msg.production_status = "FINISHED";
    return [null, msg]; 
}

let order_id = msg.order_id;

msg.order_id = order_id;
msg.topic = "UPDATE Orders SET status = 'FINISHED' WHERE order_id = ?;";

msg.payload = [order_id];

return msg;

let carts = [];
for (let i = 1; i <= 7; i++) {
    carts.push({
        cart_id: i,
        order_id: null,
        sn: null, 
        productData: null,          
        currentStation: 0, 
        state: 'IDLE'
    });
}

let stations = {
    1: null, 2: null, 3: null, 4: null, 5: null, 6: null
};

global.set('factory_fleet', carts);
global.set('factory_stations', stations);
global.set('production_priority', "A"); 

return { payload: "Factory Initialized" };

let machineAnswer = msg.payload; 
let sn = machineAnswer.sn;

let fleet = global.get('factory_fleet');
let priorityType = global.get('production_priority');

if (!fleet || !priorityType) return [msg, null, null]; 

let cart = fleet.find(c => c.sn === sn);
if (!cart || cart.state === 'IDLE') return [msg, null, null];


if (cart.currentStation === 1 && machineAnswer.response === "ACK") {

    let currentType = cart.productData.product_type; 
    let order_id = cart.order_id;

    if (currentType !== priorityType) {
        let dbUpdateMsg = {
            topic: "UPDATE Orders SET product_type = ? WHERE order_id = ?;",
            payload: [priorityType, order_id],
            order_id: order_id,
            sn: sn,
            newType: priorityType
        };

        let newAction = "NEW PRIORITY";
        let commandMsg = {
            payload: `[Cart ${cart.cart_id}] OVERRIDE PRIORITY ! Abort previous action. NEW TYPE: ${priorityType} | NEW ACTION: ${newAction}`
        };

        cart.productData.product_type = priorityType;
        global.set('factory_fleet', fleet);

        return [null, dbUpdateMsg, commandMsg];
    }
}

return [msg, null, null];

let sn = msg.sn;
let productData = msg.payload[0];

if (!sn || !productData) return null;

let fleet = global.get('factory_fleet');
if (!fleet) return null;

let cart = fleet.find(c => c.sn === sn);
if (!cart) return null;

productData.order_id = cart.order_id;
cart.productData = productData;

global.set('factory_fleet', fleet);

global.set('factory_fleet', fleet);

return { payload: `[Cart ${cart.cart_id}] Cart Update for product : ${productData.product_type} !` };

let newType = msg.newType;
let sn = msg.sn;
let order_id = msg.order_id;

let dbUpdateMsg = {
            topic: "SELECT o.order_id, o.product_type, p.* FROM Orders o JOIN Products p ON o.product_type = p.product_type JOIN Production pr ON o.order_id = ?;",
            payload: [order_id],
            sn: sn,
            newType: newType
        };

return dbUpdateMsg;

let formData = msg.payload;

msg.topic = "INSERT INTO Orders (order_id, nb_product, product_type, status) VALUES (1,?, ?, 'WAITING');";

msg.payload = [formData.nb_product, formData.product_type];

return msg;

msg.topic = `
    SELECT o.order_id, o.product_type, p.* FROM Orders o 
    JOIN Products p ON o.product_type = p.product_type 
    WHERE o.status = 'WAITING' 
    LIMIT 1;
`;
return msg;

let data = msg.productData;

let sn = data.order_id; 

msg.numSerie = sn;

msg.topic = "INSERT INTO Production (productSN, order_id, cart_id, current_station, status) VALUES (?, ?, 1, 'Station1', 'IN_PROGRESS');";

msg.payload = [sn, data.order_id];

return msg;

let data = msg.payload[0]; 

msg.productData = data;
msg.topic = "UPDATE Orders SET status = 'IN_PROGRESS' WHERE order_id = ?;";

msg.payload = [data.order_id]; 

return msg;

let data = msg.productData;

let sn = msg.numSerie; 

let stateCart = {
    sn: sn,
    order_id: data.order_id,
    productData: data,
    currentStation: 1,
    state: 'EVALUATION',
    isBypassed: false
};

flow.set('cart_' + sn, stateCart);

msg.payload = { action: 'DECISION', sn: sn };
return msg;

let sn = msg.payload.sn;
let cart = flow.get('cart_' + sn);

if (!cart) return null; 
if (cart.state !== 'EVALUATION') return null;

let numStation = cart.currentStation;

if (numStation > 6) {
    msg.topic = `UPDATE Production SET status = 'FINISHED' WHERE productSN = ${sn};`;
    flow.set('cart_' + sn, undefined);
    return [msg, { payload: `[Product ${sn}] Production finished !` }];
}

let dbUpdateMsg = {
    topic: `UPDATE Production SET current_station = 'Station${numStation}' WHERE productSN = ${sn};`
};

let commandMsg = { payload: {} };
let stopCol = "Station" + numStation + "Stop";
let opCol = "Station" + numStation + "Op";

cart.state = 'ACK_WAIT';

if (cart.productData[stopCol] === 1 || cart.productData[stopCol] === true) {
    cart.isBypassed = false;
    commandMsg.payload = `[Product ${sn} -> Station ${numStation}] INSTRUCTION : ${cart.productData[opCol]}`;
} else {
    cart.isBypassed = true;
    commandMsg.payload = `[Product ${sn} -> Station ${numStation}] CHECK-IN ONLY (Bypass)`;
}

flow.set('cart_' + sn, cart);

return [dbUpdateMsg, commandMsg];

let machineAnswer = msg.payload; 
let sn = machineAnswer.sn;
let cart = flow.get('cart_' + sn);

if (!cart) return null;

if (machineAnswer.response === "ACK" && cart.state === 'ACK_WAIT') {

    if (cart.isBypassed === true) {
        cart.state = 'EVALUATION';
        cart.currentStation++;
        flow.set('cart_' + sn, cart);

        return [
            { payload: `[Product ${sn} -> Station ${cart.currentStation - 1}] ACK received. BYPASSING... MOVE CART !` }, 
            { payload: { action: 'DECISION', sn: sn } } 
        ];
    } else {
        cart.state = 'DONE_WAIT';
        flow.set('cart_' + sn, cart);

        return { payload: `[Product ${sn} -> Station ${cart.currentStation}] ACK received. Operation in progress...` };
    }
}

if (machineAnswer.response === "DONE" && cart.state === 'DONE_WAIT') {
    cart.state = 'EVALUATION';
    cart.currentStation++;
    flow.set('cart_' + sn, cart);

    return [
        { payload: `[Product ${sn} -> Station ${cart.currentStation - 1}] DONE received. MOVE CART !` }, 
        { payload: { action: 'DECISION', sn: sn } }     ];
}

return null;
